import pytest

def test_create_leave_request_missing_mandatory_field_returns_400(
    manager_session,       # <fixture>
    base_url,              # <fixture>
    valid_leave_payload    # <fixture>
):
    incomplete_payload = {k: v for k, v in valid_leave_payload.items()
                          if k != "start_date"}

    resp = manager_session.post(
        f"{base_url}/leave-requests",
        json=incomplete_payload
    )
    assert resp.status_code == 400, (
        f"Expected 400 for missing field, got {resp.status_code}: {resp.text}"
    )
    error_body = resp.json()
    field_errors = str(error_body).lower()
    assert "start_date" in field_errors, (
        "Error response should reference the missing 'start_date' field"
    )

