import requests

def test_unauthenticated_request_returns_401(
    base_url   # <fixture>
):
    resp = requests.post(
        f"{base_url}/leave-requests",
        json={"leave_type": "annual", "start_date": "2025-08-01", "end_date": "2025-08-05"},
        timeout=10
    )
    assert resp.status_code == 401, (
        f"Expected 401 for unauthenticated request, got {resp.status_code}: {resp.text}"
    )

